// Metadata interfaces (DatasetMetadata, KeyValueStoreMetadata,
// RequestQueueMetadata) and the KeyValueStoreRecord interface are
// auto-generated by napi-rs from `#[napi(object)]` structs in src/models.rs â€”
// the metadata datetime fields come through as native `Date` (thanks to napi's
// `chrono_date` feature) and the record's `value` comes through as a `Buffer`.

export interface DatasetItemsListPage {
    count: number;
    offset: number;
    limit: number;
    total: number;
    desc: boolean;
    items: Record<string, unknown>[];
}

export interface KeyValueStoreStreamRecord {
    key: string;
    contentType: string;
    size: number;
    stream: ReadableStream<Uint8Array>;
}

export interface KeyValueStoreRecordMetadata {
    key: string;
    contentType: string;
    size: number;
}

export interface ProcessedRequest {
    requestId: string;
    uniqueKey: string;
    wasAlreadyPresent: boolean;
    wasAlreadyHandled: boolean;
}

export interface UnprocessedRequest {
    uniqueKey: string;
    url: string;
    method?: string;
}

export interface AddRequestsResponse {
    processedRequests: ProcessedRequest[];
    unprocessedRequests: UnprocessedRequest[];
}

