export interface DatasetMetadata {
    id: string;
    name?: string;
    accessedAt: Date;
    createdAt: Date;
    modifiedAt: Date;
    itemCount: number;
}

export interface KeyValueStoreMetadata {
    id: string;
    name?: string;
    accessedAt: Date;
    createdAt: Date;
    modifiedAt: Date;
}

/**
 * A KVS record returned by `getValue`: the raw value bytes as a `Buffer`
 * alongside the key, content type, and size. Replaces the hand-written
 * `KeyValueStoreRecord` interface that used to live in `dts-header.d.ts` â€”
 * the `value: Buffer` now crosses the FFI directly instead of as a per-byte
 * JSON number array.
 */
export interface KeyValueStoreRecord {
    key: string;
    contentType: string;
    /**
     * Byte length of the value. Typed `f64` so it crosses the FFI as a JS
     * `number` (matching crawlee's `KeyValueStoreItemData.size: number`)
     * without the 4 GiB ceiling a `u32` would impose; a `usize` length is
     * exact in an `f64` up to 2^53 bytes (8 PiB), well beyond any KVS record.
     */
    size: number;
    value: Buffer;
}

/**
 * The content-type sentinel for null KVS values (stored on disk as an empty
 * file). Re-exported from the core crate so consumers reference the shared
 * constant instead of hardcoding the `application/x-none` literal.
 */
export const NONE_CONTENT_TYPE: string;

export interface RequestQueueMetadata {
    id: string;
    name?: string;
    accessedAt: Date;
    createdAt: Date;
    modifiedAt: Date;
    hadMultipleClients: boolean;
    handledRequestCount: number;
    pendingRequestCount: number;
    totalRequestCount: number;
}
